const SessionState = @import("session_state.zig").SessionState;

pub const ListSessionsRequest = struct {
    /// The maximum number of sessions to return.
    max_results: ?i32,

    /// A token generated by the Athena service that specifies where to continue
    /// pagination if a previous request was truncated. To obtain the next set of
    /// pages, pass in
    /// the `NextToken` from the response object of the previous page call.
    next_token: ?[]const u8,

    /// A filter for a specific session state. A description of each state follows.
    ///
    /// `CREATING` - The session is being started, including acquiring
    /// resources.
    ///
    /// `CREATED` - The session has been started.
    ///
    /// `IDLE` - The session is able to accept a calculation.
    ///
    /// `BUSY` - The session is processing another task and is unable to accept a
    /// calculation.
    ///
    /// `TERMINATING` - The session is in the process of shutting down.
    ///
    /// `TERMINATED` - The session and its resources are no longer running.
    ///
    /// `DEGRADED` - The session has no healthy coordinators.
    ///
    /// `FAILED` - Due to a failure, the session and its resources are no longer
    /// running.
    state_filter: ?SessionState,

    /// The workgroup to which the session belongs.
    work_group: []const u8,

    pub const json_field_names = .{
        .max_results = "MaxResults",
        .next_token = "NextToken",
        .state_filter = "StateFilter",
        .work_group = "WorkGroup",
    };
};
